// Simple Supabase REST client (no SDK needed)
var SB = {
  _headers: {
    'apikey': SB_KEY,
    'Authorization': 'Bearer ' + SB_KEY,
    'Content-Type': 'application/json',
    'Prefer': 'return=representation'
  },

  // SELECT
  from: function(table) {
    return {
      _table: table,
      _filters: [],
      _select: '*',
      eq: function(col, val) { this._filters.push(col+'=eq.'+encodeURIComponent(val)); return this; },
      select: function(cols) { this._select = cols; return this; },
      single: function() { this._single = true; return this; },
      get: function() {
        var url = SB_URL+'/rest/v1/'+this._table+'?select='+this._select;
        if(this._filters.length) url += '&'+this._filters.join('&');
        if(this._single) url += '&limit=1';
        return fetch(url, {headers: SB._headers}).then(function(r){return r.json();});
      },
      // UPSERT
      upsert: function(data) {
        return fetch(SB_URL+'/rest/v1/'+this._table, {
          method: 'POST',
          headers: Object.assign({}, SB._headers, {'Prefer':'resolution=merge-duplicates,return=representation'}),
          body: JSON.stringify(Array.isArray(data) ? data : [data])
        }).then(function(r){return r.json();});
      },
      // DELETE
      delete: function(col, val) {
        return fetch(SB_URL+'/rest/v1/'+this._table+'?'+col+'=eq.'+encodeURIComponent(val), {
          method: 'DELETE',
          headers: SB._headers
        }).then(function(r){ return r.ok ? {ok:true} : r.json(); });
      }
    };
  }
};

