function classBadge(c, mastery){
  var icon = classIcon(c);
  var stars = mastery ? Array(mastery+1).join('★') : '';
  return '<span style="display:inline-flex;align-items:center;gap:4px;background:var(--bg3);border:1px solid var(--b1);border-radius:3px;padding:3px 8px;font-size:11px;margin:2px;vertical-align:middle">'
    +'<span style="display:inline-flex;color:var(--gold)">'+icon+'</span>'
    +' <span style="color:var(--tx1)">'+esc(c)+'</span>'
    +(stars?'<span style="color:var(--gold);font-size:10px;letter-spacing:1px">'+stars+'</span>':'')
    +'</span>';
}
function memberClassBadges(m){
  // m.classes = [{name, mastery}] or m.classe = string (legacy)
  if(m.classes && m.classes.length) return m.classes.map(function(c){return classBadge(c.name, c.mastery);}).join('');
  if(m.classe) return classBadge(m.classe, 0);
  return '<span style="font-size:10px;color:var(--tx4)">—</span>';
}


function mbClassSlotHTML(mb, gid, mid, canEdit){
  var classes = mb.classes||[];
  if(classes.length === 0) return mb.classe ? '<div style="font-size:7px;color:var(--teal2);margin-top:2px">'+esc(mb.classe)+'</div>' : '';
  if(classes.length === 1) {
    return '<div style="font-size:7px;color:var(--teal2);margin-top:2px;display:flex;align-items:center;gap:2px">'
      +'<span style="color:var(--gold)">'+classIcon(classes[0].name)+'</span>'
      +Array(classes[0].mastery+1).join('★')
      +'</div>';
  }
  // Multiple classes — show dropdown only if chef/officier, else show assigned class
  var g2 = gG(gid);
  var assignedClass = (g2 && g2.classAssignments && g2.classAssignments[mid]) || classes[0].name;
  if(!canEdit){
    var ac = classes.find(function(c){return c.name===assignedClass;})||classes[0];
    return '<div style="font-size:7px;color:var(--teal2);margin-top:2px;display:flex;align-items:center;gap:2px">'      +'<span style="color:var(--gold)">'+classIcon(ac.name)+'</span>'      +esc(ac.name)+' '+Array(ac.mastery+1).join('★')      +'</div>';
  }
  return '<select onchange="assignClassEl(this)" data-gid="'+gid+'" data-mid="'+mid+'"'
    +' style="width:100%;font-size:7px;background:var(--bg1);border:1px solid var(--b1);color:var(--teal2);border-radius:2px;padding:1px;margin-top:2px">'
    +classes.map(function(c){
      return '<option value="'+esc(c.name)+'"'+(assignedClass===c.name?' selected':'')+'>'+esc(c.name)+' '+Array(c.mastery+1).join('★')+'</option>';
    }).join('')
    +'</select>';
}

function assignClassEl(el){
  var g = gG(el.dataset.gid); if(!g) return;
  if(!g.classAssignments) g.classAssignments = {};
  g.classAssignments[el.dataset.mid] = el.value;
  sbSaveGroup(g).catch(function(e){console.warn('[assignClass]',e);});
}


function cpToggle(chk){
  var key=chk.dataset.key;
  var card=document.getElementById('cp-'+key);
  if(card) card.style.borderColor=chk.checked?'var(--golddim)':'var(--b1)';
  if(chk.checked){
    var masInput=document.getElementById('mas-'+key);
    if(masInput&&masInput.value==='0'){masInput.value='1';cpRenderStars(key,1);}
  }
}
function cpSetMastery(span){
  var key=span.dataset.key;
  var val=parseInt(span.dataset.val);
  var masInput=document.getElementById('mas-'+key);
  if(masInput) masInput.value=val;
  var chk=document.querySelector('.cp-check[data-key="'+key+'"]');
  if(chk&&!chk.checked){chk.checked=true;cpToggle(chk);}
  cpRenderStars(key,val);
}
function cpRenderStars(key,mastery){
  var container=document.getElementById('stars-'+key);
  if(!container) return;
  container.querySelectorAll('span[data-val]').forEach(function(s){
    s.style.color=mastery>=parseInt(s.dataset.val)?'var(--gold)':'var(--b1)';
  });
}
