function goDeep(link){
  if(!link)return;
  var parts=link.split(':');
  var page=parts[0];
  var id=parts.slice(1).join(':');
  if(!id){go(page);return;}
  if(page==='formthread'){
    var t2=(DB.forumThreads||[]).find(function(x){return x.id===id;});
    if(t2){CT=t2;FV='thread';go('form');}
    return;
  }
  if(page==='for'){
    var t=(DB.forumThreads||[]).find(function(x){return x.id===id;});
    if(t){FV='thread';CT=t;go('for');return;}
  }
  if(page==='form'){
    var f=(DB.formations||[]).find(function(x){return x.id===id;});
    if(f){FmV='detail';CFm=f;go('form');return;}
  }
  if(page==='vote'){
    go('vote');
    setTimeout(function(){var el=document.querySelector('[data-war-id="'+id+'"]');if(el)el.scrollIntoView({behavior:'smooth',block:'start'});},200);
    return;
  }
  if(page==='cal'){
    go('cal');
    if(id.indexOf('tour:')===0){
      var tid=id.slice(5);
      var tour=(DB.tournaments||[]).find(function(x){return x.id===tid;});
      if(tour){window._calTab='tournaments';window._calDetail={type:'tournament',data:tour};go('cal');}
    } else {
      setTimeout(function(){var el=document.querySelector('[data-event-id="'+id+'"]');if(el){el.style.outline='2px solid var(--gold)';el.scrollIntoView({behavior:'smooth',block:'start'});}},200);
    }
    return;
  }
  go(page);
}

function goVote(){go('vote');}
function goForm(){go('form');}
function goFor(){go('for');}
function goCal(){go('cal');}
function go(p){
  CP=p;
  try{sessionStorage.setItem('fs_cp',p);}catch(e){}
  document.querySelectorAll('.ni').forEach(function(n){n.classList.remove('active');});
  var el=document.querySelector('.ni[data-page="'+p+'"]');
  if(el)el.classList.add('active');
  var t=PG[p]||[p,''];
  document.getElementById('ttl').textContent=t[0];
  document.getElementById('tsub').textContent=t[1];
  document.getElementById('tact').innerHTML='';
  document.getElementById('content').scrollTop=0;
  // Couleur d'accent par section
  var _sc={home:'var(--gold)',mbr:'#e8943a',unit:'#64b5f6',grp:'#ef5350',vote:'#ffd54f',for:'var(--teal2)',form:'#ce93d8',cal:'#80cbc4',rec:'#ff8a65',param:'var(--tx2)',profil:'var(--gold)'};
  var _col=_sc[p]||'var(--gold)';
  var _topbar=document.getElementById('topbar');
  if(_topbar) _topbar.style.borderBottom='2px solid '+_col;
  if(el) el.style.setProperty('color',_col,'important');
  document.querySelectorAll('.ni:not(.active)').forEach(function(n){n.style.color='';});
  // Reset view state only when navigating FROM a different section
  if(p==='for'&&CP!=='for'){FV='list';CT=null;}
  if(p==='form'&&CP!=='form'){FmV='list';CFm=null;FV='list';CT=null;}
  if(p==='for')markSeen('forum');
  if(p==='form')markSeen('form');
  if(p==='vote')markSeen('vote');
  if(p==='grp')markSeen('grp');
  if(p==='cal'){markSeen('cal');}
  if(p==='home')markSeen('banner');
  var fns={home:pgHome,mbr:pgMbr,unit:pgUnit,grp:pgGrp,vote:pgVote,for:pgFor,form:pgForm,cal:pgCal,rec:pgRec,param:pgParam,profil:pgProfil,stats:pgStats,rank:pgRank,planning:pgPlanning,hier:pgHierarchy};
  document.getElementById('content').innerHTML=(fns[p]||pgHome)();
  postGo(p);
}
function postGo(p){
  if(p==='profil')postProfil();
}

